import{_ as e,o as t,c as i,a5 as l}from"./chunks/framework.B5tqjWbr.js";const C=JSON.parse('{"title":"教程 0046：PCS 储能 DC-DC 与模式状态机","description":"","frontmatter":{"title":"教程 0046：PCS 储能 DC-DC 与模式状态机","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0046-pcs-storage-dcdc-mode-state-machine.html","status":"learning","visibility":"public","summary":"Imported from 0046-pcs-storage-dcdc-mode-state-machine.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0046-pcs-storage-dcdc-mode-state-machine.md","filePath":"content/power/lessons/0046-pcs-storage-dcdc-mode-state-machine.md","lastUpdated":null}'),o={name:"content/power/lessons/0046-pcs-storage-dcdc-mode-state-machine.md"};function r(c,a,d,s,n,h){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="教程-0046-pcs-储能-dc-dc-与模式状态机" tabindex="-1">教程 0046：PCS 储能 DC-DC 与模式状态机 <a class="header-anchor" href="#教程-0046-pcs-储能-dc-dc-与模式状态机" aria-label="Permalink to &quot;教程 0046：PCS 储能 DC-DC 与模式状态机&quot;">​</a></h1><p>中文主讲。一个概念：PCS 不只是一个逆变器，还要把电池侧双向 DC-DC、并网/离网控制和安全状态机串起来。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**只讲公开 PCS 架构，不记录真实 BMS 协议、客户调度策略、继电器时序或项目阈值。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>双向 DC-DC 变换器（bidirectional DC-DC converter）连接电池和直流母线，支持充电 Buck 或放电 Boost。PCS 模式状态机（PCS mode state machine）负责待机、预充、并网充电、并网放电、离网构网、故障和安全停机之间的切换。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 课程已经有模式状态机、参数、故障锁存和通信。扩展到 PCS 后，这些软件结构仍然适用，只是控制对象从 UPS 输出供电扩展到电池能量调度、并网功率和构网供电。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>PCS 像一个能量路由器。电池、直流母线和交流电网分别是三个端口；状态机决定哪条路打开，控制器决定这条路上流多少能量。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>charge: grid -&gt; AC/DC -&gt; DC bus -&gt; DC/DC -&gt; battery discharge: battery -&gt; DC/DC -&gt; DC bus -&gt; DC/AC -&gt; grid/load allowed = precharge_ok and contactor_ok and no_fault and command_valid</p><p>功率流方向必须同时满足 BMS 允许、电池 SOC、母线电压、PCS 电流限幅和电网状态。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>设计一个简化状态机：Standby -&gt; Precharge -&gt; GridCharge -&gt; GridDischarge -&gt; GridForming -&gt; Fault。注入 BMS 禁止充电、PLL 失锁和母线过压，观察状态是否进入安全路径。</p><p>产物</p><ul><li>一张 PCS 模式状态迁移图。</li><li>一个事件表：命令、保护、允许条件、输出动作。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>模块边界可沿用 UPS C 骨架：<code>inputs</code> 采集电网和 BMS 状态，<code>protection</code> 生成故障标志，<code>mode_state_machine</code> 决定 PCS 模式，<code>outputs</code> 控制接触器、PWM 允许和通信上报。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**PCS 只要控制 P/Q 就够了。 **纠正：**能量路径、安全互锁和电池限制同样关键。</li><li>**误解：**DC-DC 和逆变器状态可以各管各的。 **纠正：**母线电压和故障闭环要求统一状态机协调。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能画出 PCS 电池、DC-DC、DC bus、DC/AC、电网的能量路径。</li><li>能列出并网充电、并网放电、离网构网的进入条件。</li><li>能说明故障闭环如何关闭 PWM、断开接触器并上报状态。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>BMS 禁止放电时，PCS 状态机应该如何处理放电命令？</li><li>母线预充未完成时，为什么不能直接开 PWM？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>真实 PCS 工程中，BMS 限制、PCS 故障和调度命令谁的优先级最高？</li><li>我只记录通用优先级原则，不记录客户协议和项目参数。</li></ul><p>**下一步：**可以把 PCS 状态机迁移到现有 C 固件骨架，作为后续项目练习。</p><p>源稿：<code>concepts/pcs/storage-dcdc-mode-state-machine.md</code></p><p>上一节：教程 0045：PCS LCL 滤波器与有源阻尼下一节：教程 0047：TMS320F28075 外设从零配置</p>',31)])])}const u=e(o,[["render",r]]);export{C as __pageData,u as default};
